#include<bits/stdc++.h>
using namespace std;
struct sxj
{
    long long a[51];
    sxj()
    {
        memset(a,0,sizeof(a));
    }
    void insert(long long x)
    {
        for(long long i=30;i>=0;i--)
        {
            if(x&(1ll<<i))
            {
                if(a[i])
                {
                    x^=a[i];
                }
                else
                {
                    a[i]=x;
                    return;
                }
            }
        }
    }
    long long getmax()
    {
        long long ans=0;
        for(long long i=30;i>=0;i--)
        {
            ans=max(ans,ans^a[i]);
        }
        return ans;
    }
}ans;
struct segment_tree
{
    struct node
    {
        long long l,r;
        sxj sum;
        long long lson,rson;
    }a[150010];
    long long cnt;
    segment_tree():cnt(0){}
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        return x;
    }
    void add(long long x,long long p,long long v)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        a[x].sum.insert(v);
        if(a[x].l==a[x].r)
        {
            return;
        }
        add(a[x].lson,p,v);
        add(a[x].rson,p,v);
    }
    void query(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            for(long long i=0;i<=31;i++)
            {
                if(a[x].sum.a[i])
                {
                    ans.insert(a[x].sum.a[i]);
                }
            }
            return;
        }
        query(a[x].lson,l,r);
        query(a[x].rson,l,r);
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    t.init(1,m);
    for(long long i=1;i<=n;i++)
    {
        long long op,x,y;
        scanf("%lld%lld%lld",&op,&x,&y);
        if(op==1)
        {
            t.add(1,x,y);
        }
        else
        {
            for(long long i=0;i<=50;i++)
            {
                ans.a[i]=0;
            }
            t.query(1,x,y);
            printf("%lld\n",ans.getmax());
        }
    }
    return 0;
}
